import heapq
from dataclasses import dataclass

@dataclass(order=True)
class Scored:
    score: float
    chunk: str

def top_k(scored, k):
    heap: list[Scored] = []
    for s in scored:
        if len(heap) < k:
            heapq.heappush(heap, s)
        elif s.score > heap[0].score:        # better than current worst-of-top-k
            heapq.heapreplace(heap, s)
    return sorted(heap, key=lambda x: -x.score)

results = [Scored(0.42, 'A'), Scored(0.91, 'B'), Scored(0.55, 'C'), Scored(0.88, 'D')]
print(top_k(results, 2))   # [Scored(0.91,'B'), Scored(0.88,'D')]
